import groovy.json.JsonSlurper 

def response = messageExchange.response.responseContent
def slurper = new JsonSlurper()
def json = slurper.parseText response

//Obtain Status code
def responseCode = context.testCase.testSteps["Request 1"].testRequest.response.responseHeaders["#status#"].toString()

//Check if Status code = 200
if(responseCode.contains("200"))
assert json.toString().contains("TOMADOR")
else
assert false

//Print out Status code
//log.info responseCode​

